-- RESTAURANT LOCATIONS & HOURS & PAYMENTS --
SELECT restaurant_branch_id,
       day_of_week,
       open_time,
       close_time,
       COUNT(*)
FROM opening_hours
WHERE restaurant_branch_id BETWEEN 41 AND 44
GROUP BY restaurant_branch_id,
         day_of_week,
         open_time,
         close_time
HAVING COUNT(*) > 1;
DELETE FROM opening_hours
WHERE ctid IN (
    SELECT ctid
    FROM (
             SELECT ctid,
                    ROW_NUMBER() OVER (
                        PARTITION BY restaurant_branch_id,
                            day_of_week,
                            open_time,
                            close_time
                        ORDER BY ctid
                        ) AS rn
             FROM opening_hours
         ) t
    WHERE rn > 1
);
